Code.Terraform:
```hcl
# Terraform：抑制所有 ACTIVE Inspector 发现
resource "aws_inspector2_filter" "<example_resource_name>" {
  name   = "<example_resource_name>"
  action = "SUPPRESS"  # 关键：将匹配的发现转换为抑制状态，而不是活动状态

  filter_criteria {
    finding_status {
      comparison = "EQUALS"
      value      = "ACTIVE"  # 关键：针对所有活动发现
    }
  }
}
```
